// interface `permission` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod permission {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_LOOKUP: u16 = 1;
	pub const OP_AUDIT: u16 = 2;
	pub const OP_RUN: u16 = 3;

	pub trait Service {
		fn lookup(&mut self, component: String) -> Result<Manifest, Error>;
		fn audit(&mut self) -> Result<Vec<AuditEntry>, Error>;
		fn run(&mut self, name: String, args: String, cwd: String, stdout: u64) -> Result<StartResult, Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = Reader::with_handle(request, request_handle);
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		match op {
			OP_LOOKUP => {
				let component = r.string_lp()?;
				let result = service.lookup(component);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v141) => {
							w.u8(1)?;
							v141.write(w)?;
						}
						Err(v142) => {
							w.u8(0)?;
							v142.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_AUDIT => {
				let result = service.audit();
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v143) => {
							w.u8(1)?;
							if v143.len() > u16::MAX as usize {
								return None;
							}
							w.u16(v143.len() as u16)?;
							for v145 in v143.iter() {
								v145.write(w)?;
							}
						}
						Err(v144) => {
							w.u8(0)?;
							v144.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_RUN => {
				let name = r.string_lp()?;
				let args = r.string_lp()?;
				let cwd = r.string_lp()?;
				let stdout = {
					let _ = r.u32()?;
					r.take_handle()
				};
				let result = service.run(name, args, cwd, stdout);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v146) => {
							w.u8(1)?;
							v146.write(w)?;
						}
						Err(v147) => {
							w.u8(0)?;
							v147.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn lookup(&mut self, component: &str) -> Option<Result<Manifest, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_LOOKUP)?;
			w.u32(corr)?;
			w.bytes_lp(component.as_bytes())?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(Manifest::read(r)?) } else { Err(Error::read(r)?) })
		}
		pub fn audit(&mut self) -> Option<Result<Vec<AuditEntry>, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_AUDIT)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 {
				Ok({
					let v148 = r.u16()? as usize;
					let mut v149 = Vec::new();
					for _ in 0..v148 {
						v149.push(AuditEntry::read(r)?);
					}
					v149
				})
			} else {
				Err(Error::read(r)?)
			})
		}
		pub fn run(&mut self, name: &str, args: &str, cwd: &str, stdout: &u64) -> Option<Result<StartResult, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_RUN)?;
			w.u32(corr)?;
			w.bytes_lp(name.as_bytes())?;
			w.bytes_lp(args.as_bytes())?;
			w.bytes_lp(cwd.as_bytes())?;
			w.set_handle(*stdout);
			w.u32(0)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(StartResult::read(r)?) } else { Err(Error::read(r)?) })
		}
	}
}

